const Joi = require('joi');

const productSchema = Joi.object({
  name: Joi.string().required().min(3).max(100),
  price: Joi.number().required().positive().max(10000),
  category: Joi.string().required().valid('electronics', 'clothing', 'books', 'other'),
  stock: Joi.number().integer().required().min(0).max(1000),
  isAvailable: Joi.boolean().default(true)
});

const validateProduct = (req, res, next) => {
  const { error, value } = productSchema.validate(req.body, { abortEarly: false });

  if (error) {
    const errors = error.details.map(detail => detail.message);
    return res.status(400).json({ 
      message: 'Erreur de validation des données',
      errors: errors 
    });
  }

  // Remplacer req.body par la valeur validée (inclut les valeurs par défaut)
  req.body = value;
  next();
};

// Utilisation dans la route
app.post('/api/products', validateProduct, (req, res) => {
  // req.body est déjà validé
  res.status(201).json(req.body);
});

const z = require('zod');

const registerSchema = z.object({
  email: z.string().email('Email invalide'),
  password: z.string()
    .min(8, 'Le mot de passe doit contenir au moins 8 caractères')
    .regex(/[A-Z]/, 'Doit contenir au moins une majuscule')
    .regex(/[a-z]/, 'Doit contenir au moins une minuscule')
    .regex(/[0-9]/, 'Doit contenir au moins un chiffre'),
  age: z.number().int('Doit être un entier').min(13, 'Âge minimum 13 ans').max(120, 'Âge maximum 120 ans'),
  newsletter: z.boolean().default(false)
}).strict();

function validateRegister(inputData) {
  try {
    const validData = registerSchema.parse(inputData);
    return {
      success: true,
      data: validData,
      errors: null
    };
  } catch (error) {
    if (error instanceof z.ZodError) {
      const errors = error.errors.map(err => `${err.path.join('.')} : ${err.message}`);
      return {
        success: false,
        data: null,
        errors: errors
      };
    }
    return {
      success: false,
      data: null,
      errors: ['Erreur inconnue']
    };
  }
}

// Exemple d'utilisation dans un middleware Express
app.post('/api/register', (req, res) => {
  const result = validateRegister(req.body);
  if (!result.success) {
    return res.status(400).json({ errors: result.errors });
  }
  // result.data contient les données validées
  res.status(201).json({ message: 'Utilisateur créé', user: result.data });
});

// Version avec Zod
const z = require('zod');

// Schéma pour req.params
const paramsSchema = z.object({
  id: z.string().regex(/^\d+$/, 'ID doit être un entier').transform(Number).pipe(z.number().int().positive('ID doit être positif'))
});

// Schéma pour req.query
const querySchema = z.object({
  page: z.coerce.number().int().min(1).default(1),
  limit: z.coerce.number().int().min(1).max(100).default(10),
  sort: z.enum(['asc', 'desc']).default('asc')
});

// Middleware de validation combiné
const validateGetComments = (req, res, next) => {
  try {
    req.params = paramsSchema.parse(req.params);
    req.query = querySchema.parse(req.query);
    next();
  } catch (error) {
    if (error instanceof z.ZodError) {
      return res.status(400).json({ 
        message: 'Paramètres invalides', 
        errors: error.errors.map(e => `${e.path.join('.')} : ${e.message}`)
      });
    }
    next(error);
  }
};

app.get('/api/posts/:id/comments', validateGetComments, (req, res) => {
  const { id } = req.params;    // id est un nombre
  const { page, limit, sort } = req.query;
  res.json({ id, page, limit, sort });
});

// Middleware générique de validation
const validate = (schemas) => {
  return (req, res, next) => {
    const errors = {};

    try {
      if (schemas.body) req.body = schemas.body.parse(req.body);
    } catch (e) { errors.body = e.errors; }

    try {
      if (schemas.query) req.query = schemas.query.parse(req.query);
    } catch (e) { errors.query = e.errors; }

    try {
      if (schemas.params) req.params = schemas.params.parse(req.params);
    } catch (e) { errors.params = e.errors; }

    if (Object.keys(errors).length > 0) {
      return res.status(400).json({ 
        message: 'Erreur(s) de validation', 
        details: errors 
      });
    }

    next();
  };
};

// Utilisation
app.post('/api/users/:id', 
  validate({
    params: z.object({ id: z.string().uuid() }),
    body: z.object({ name: z.string().min(2), email: z.string().email() })
  }), 
  (req, res) => { /* ... */ }
);
